<template>
	<div v-show="show">
		<el-dialog title="编辑房源" :visible.sync="dialogVisible" width="450px" top="3px">
			<el-form :model="form" label-width="80px" size="small" :rules="rules">
				<el-form-item label="房屋简介">
					<el-input :rows="3" placeholder="请输入房屋介绍" maxlength="200" type="textarea" v-model="form.description"
						show-word-limit></el-input>
				</el-form-item>
				<el-form-item label="所在地" prop="location">
					<el-cascader :options="options" v-model="form.selectedOptions" @change="handleChange">
					</el-cascader>
				</el-form-item>
				<el-form-item label="小区名称" prop="address">
					<el-autocomplete class="inline-input" v-model="form.address" :fetch-suggestions="querySearch"
						placeholder="请输入小区名称并选择" :trigger-on-focus="false" @select="handleSelect"></el-autocomplete>
				</el-form-item>
				<el-form-item label="详细地址" prop="detailedAddress">
					<el-input placeholder="请输入详细地址" v-model="form.detailedAddress"></el-input>
				</el-form-item>

				<el-form-item label="期望租金" prop="price">
					<el-input oninput="value=value.replace(/[^0-9.]/g,'')" placeholder="请输入期望租金" v-model="form.price">
						<template slot="prepend">￥</template>
						<template slot="append">元 / 月</template>
					</el-input>
				</el-form-item>
				<el-form-item label="面积" prop="area">
					<el-input oninput="value=value.replace(/[^0-9.]/g,'')" placeholder="请输入面积" v-model="form.area">
						<template slot="append">平方米</template>
					</el-input>
				</el-form-item>
				<el-form-item label="装修风格">
					<el-radio-group v-model="form.decorationStyle">
						<el-radio label="简装修"></el-radio>
						<el-radio label="精装修"></el-radio>
					</el-radio-group>
				</el-form-item>
				<el-form-item label="户型">
					<el-input-number size="small" v-model="form.rooms" :min="0" :max="10" label="房">
					</el-input-number>&nbsp;&nbsp;房&nbsp;&nbsp;
					<el-input-number size="small" v-model="form.halls" :min="0" :max="10" label="厅">
					</el-input-number>&nbsp;&nbsp;厅
					<el-input-number size="small" v-model="form.bathrooms" :min="0" :max="10" label="卫">
					</el-input-number>&nbsp;&nbsp;卫
				</el-form-item>
				<el-form-item label="房屋朝向" prop="orientation">
					<el-checkbox-group v-model="form.orientation">
						<el-checkbox label="北"></el-checkbox>
						<el-checkbox label="东"></el-checkbox>
						<el-checkbox label="南"></el-checkbox>
						<el-checkbox label="西"></el-checkbox>
					</el-checkbox-group>
				</el-form-item>

			</el-form>
			<span slot="footer" class="dialog-footer">
				<el-button @click="dialogVisible=false" size="small">取 消</el-button>
				<el-button type="primary" @click="onClickDialogConfirm" size="small">确 定</el-button>
			</span>
		</el-dialog>


		<el-dialog title="指定中介负责人" :visible.sync="pvisible" width="200px" top="3px">


			<el-select v-model="principal" placeholder="指定中介负责人">
				<el-option v-for="item in adminList" :key="item.id" :label="item.username" :value="item.id">
				</el-option>
			</el-select>
			</el-form>
			<span slot="footer" class="dialog-footer">
				<el-button @click="pvisible=false" size="small">取 消</el-button>
				<el-button type="primary" @click="onClickPublishConfirm" size="small">确 定</el-button>
			</span>
		</el-dialog>


		<div class="fixed" v-if="$route.params.isAdmin==true&&houseInfo.status!=2">
			<el-popconfirm ref="ppp" confirm-button-type="danger" title="确定删除吗？" @confirm="onClickDelete">
				<el-button slot="reference" type="danger" style="margin-right: 10px;"><i class="el-icon-delete-solid"></i>
					删除</el-button>
			</el-popconfirm>


			<el-button type="warning" @click="dialogVisible=true"><i class="el-icon-s-tools"></i> 编辑</el-button>
			<!-- <el-button type="success" @click="onClickPublish" v-if="houseInfo.status==0"><i class="el-icon-success"></i>
				发布</el-button> -->




			<el-button type="success" @click="pvisible=true" v-if="houseInfo.status==0"><i class="el-icon-success"></i>
				发布</el-button>


			<el-button type="info" @click="onClickLock" v-if="houseInfo.status==1"><i class="el-icon-remove"></i> 锁定
			</el-button>
			<el-button type="success" @click="onClickRecover" v-if="houseInfo.status==3"><i class="el-icon-refresh-right"></i>
				恢复</el-button>
		</div>
		<el-button class="fixed_user" v-if="$route.params.isAdmin==false" type="" @click="back">
			<i class="el-icon-caret-left"></i>返回
		</el-button>


		<div class="main">
			<el-row>
				<el-col :span="15">
					<div class="carousel"
						style="background-color: rgb(247,247,247);border-right:2px solid rgb(64,158,255);border-bottom:2px solid rgb(64,158,255);">
						<el-carousel height="480px">
							<el-carousel-item v-for="item in imageList">
								<img :src="common.pictureURL + item.r" style="width: 100%;height: 100%;object-fit: cover;">
							</el-carousel-item>
						</el-carousel>
					</div>
				</el-col>
				<el-col :span="9">
					<div class="info">
						<h1>{{houseInfo.address}}</h1>
						<div>		<div style="display: inline; color: rgb(64,158,255);font-size: 24px;font-weight: bold;">￥{{houseInfo.price}}元 / 月</div>
						<div style="display: inline;float: right;font-weight: bold;margin-top: 10px;">No.{{houseInfo.id}}</div>
						</div>
				
						<el-divider></el-divider>
						<el-row :gutter="10">
							<el-col :span="8">
								<div>
									<el-statistic title="面积">
										<template slot="formatter"> {{houseInfo.area}}㎡</template>
									</el-statistic>
								</div>
							</el-col>
							<el-col :span="8">
								<div>
									<el-statistic title="户型">
										<template slot="formatter">
											{{houseInfo.rooms}}房{{houseInfo.halls}}厅{{houseInfo.bathrooms}}卫 </template>
									</el-statistic>
								</div>
							</el-col>
							<el-col :span="8">
								<div>
									<el-statistic title="朝向">
										<template slot="formatter"> {{houseInfo.orientation}} </template>
									</el-statistic>
								</div>
							</el-col>
						</el-row>
						<el-divider></el-divider>
						<el-descriptions :column="1" border style="margin-bottom: 13px;">
							<el-descriptions-item labelStyle="width: 95px;">
								<template slot="label">
									<i class="el-icon-location-outline"></i>
									所在地
								</template>
								{{location}}
							</el-descriptions-item>
							<el-descriptions-item>
								<template slot="label">
									<i class="el-icon-office-building"></i>
									详细地址
								</template>
								{{houseInfo.detailedAddress}}
							</el-descriptions-item>
							<el-descriptions-item>
								<template slot="label">
									<i class="el-icon-tickets"></i>
									装修风格
								</template>
								<el-tag type="info"><b>{{decorationStyle}}</b></el-tag>
							</el-descriptions-item>
							<el-descriptions-item>
								<template slot="label">
									<i class="el-icon-loading"></i>
									状态
								</template>
								<el-tag><b>{{status}}</b></el-tag>
							</el-descriptions-item>

						</el-descriptions>

					</div>
				</el-col>
			</el-row>
			<div class="detailedinfo" style="margin: 20px;">
				<el-divider></el-divider>
				<div style="overflow: hidden;">
					<div style="float: left;margin-top: 10px;">
						<i class="el-icon-user-solid"></i>{{houseInfo.addName}}&nbsp;&nbsp;
						发布于：{{houseInfo.addTime}}
						<div v-if="publishAudit!=null" style="display: inline;">
							<el-divider direction="vertical"></el-divider>
							<i class="el-icon-user-solid"></i>{{publishAudit[0]}}&nbsp;&nbsp;
							审核于：{{publishAudit[1]}}
						</div>
						<el-divider direction="vertical"></el-divider>
					</div>
					<!-- 	<el-popconfirm ref="pp" title="确定发起订单？" @confirm="onClickConfirmBooking">
						<el-button v-show="$route.params.isAdmin==false" :disabled="bookButtonDisabled" slot="reference" style="float: right;margin-left: 10px;" type="primary">{{bookButtonDisabled?'已预定该房源':'预定房源'}}</el-button>
					</el-popconfirm> -->

					<el-popover ref="pp" placement="top" width="150" trigger="click" v-model="bookpopvisible">
						确定要预定该房源吗？<br>
						请选择租期（月）：<br> <el-input-number size="small" style="margin: 20px auto;" v-model="bookingduration" :min="1"
							label="月"></el-input-number>
						<div style="text-align: right; margin: 0">
							<el-button size="mini" type="text" @click="bookpopvisible = false">取消</el-button>
							<el-button type="primary" size="mini" @click="onClickConfirmBooking">确定</el-button>
						</div>
						<el-button v-show="$route.params.isAdmin==false" :disabled="bookButtonDisabled" slot="reference"
							style="float: right;margin-left: 10px;" type="primary">{{bookButtonDisabled?'已预定该房源':'预定房源'}}</el-button>
					</el-popover>

					<el-button v-if="$route.params.isAdmin==false" type="warning" :plain="plain"
						style="float: right;width: 100px;" @click="onClickCollect">{{plain?'收藏':'取消收藏'}}</el-button>
				</div>
				<el-divider></el-divider>
				<el-row>
					<el-col :span="12">
						<div>
							<el-descriptions style="margin-right: 20px;" title="发布人信息" :column="1" border>
								<el-descriptions-item>
									<template slot="label">
										<i class="el-icon-user"></i>
										用户名
									</template>
									{{landlordInfo.username}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										<i class="el-icon-user"></i>
										姓名
									</template>
									{{landlordInfo.name}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										<i class="el-icon-mobile-phone"></i>
										手机号
									</template>
									{{landlordInfo.phone}}
								</el-descriptions-item>
							</el-descriptions>
						</div>
					</el-col>
					<el-col :span="12">
						<div>
							<div v-if="publishAudit!=null">
								<el-descriptions title="中介负责人信息" :column="1" border>
									<el-descriptions-item>
										<template slot="label">
											<i class="el-icon-user"></i>
											用户名
										</template>
										{{principalInfo.username}}
									</el-descriptions-item>
									<el-descriptions-item>
										<template slot="label">
											<i class="el-icon-user"></i>
											姓名
										</template>
										{{principalInfo.name}}
									</el-descriptions-item>
									<el-descriptions-item>
										<template slot="label">
											<i class="el-icon-mobile-phone"></i>
											手机号
										</template>
										{{principalInfo.phone}}
									</el-descriptions-item>
								</el-descriptions>
							</div>
						</div>
					</el-col>
				</el-row>


				<el-divider></el-divider>
				<h3>房源简介</h3>
				<p>{{houseInfo.description}}</p>
				<el-divider></el-divider>
				<div v-if="$route.params.isAdmin==false">
					<h2>通勤时间</h2>
					<el-descriptions class="margin-top" :column="4" border>
						<el-descriptions-item>
							<template slot="label">
								<svg t="1680249209724" class="icon" viewBox="0 0 1024 1024" version="1.1"
									xmlns="http://www.w3.org/2000/svg" p-id="3662" width="16" height="16">
									<path
										d="M912.832 467.104h-22.272l-6.624-22.464h60.928a32 32 0 1 0 0-64h-79.808l-35.584-120.544C815.168 221.28 771.52 192 728 192H302.592c-43.52 0-87.136 29.28-102.112 70.112l-34.944 118.528H96a32 32 0 0 0 0 64h50.624l-6.624 22.464H128c-35.296 0-64 28.704-64 64v282.944h51.104v34.816a32 32 0 1 0 64 0v-34.816h690.528v34.816a32 32 0 1 0 64 0v-34.816h43.232v-282.944a64.128 64.128 0 0 0-64.032-64zM128 750.016v-104.96h73.792c26.464 0 50.528-16.672 59.872-41.408l24.064-63.712c1.088-2.912 1.216-5.888 1.44-8.832h450.528c0.224 2.944 0.352 5.92 1.44 8.832l24.064 63.648a64.256 64.256 0 0 0 59.872 41.472h89.76v104.96H128z m784.832-168.96l-89.76-0.032-18.848-49.952h108.608v49.984zM218.528 426.944a30.944 30.944 0 0 0 2.816-9.568L261.184 282.24c4.48-12.16 23.52-26.24 41.408-26.24H728c17.888 0 36.928 14.08 40.736 24.192l55.104 186.88H206.72l11.808-40.128z m2.144 104.16l-18.88 49.984H128v-49.984h92.672z"
										p-id="3663"></path>
									<path d="M614.752 626.24h-188.64a32 32 0 1 0 0 64h188.64a32 32 0 1 0 0-64z" p-id="3664"></path>
								</svg>
								驾车
							</template>
							{{distanceInfo.driving.duration}}
						</el-descriptions-item>
						<el-descriptions-item>
							<template slot="label">
								<svg t="1680252944468" class="icon" viewBox="0 0 1024 1024" version="1.1"
									xmlns="http://www.w3.org/2000/svg" p-id="2577" width="16" height="16">
