<script>
	import {
		regionData,
		CodeToText,
	} from 'element-china-area-data'
	import RecommendedUser from '../components/RecommendedUser.vue'
	export default {
		data() {
			var validatePass = (rule, value, callback) => {
				if (this.form.selectedOptions == null) {
					callback(new Error('请选择'));
				} else {
					callback()
				}
			}

			return {
				bookingduration: 1, //租期
				bookpopvisible: false,
				bookButtonDisabled: false,
				plain: true, //收藏按钮plain属性
				distanceInfo: {
					transit: {
						duration: '',
						distance: '',
					},
					driving: {
						duration: '',
						distance: '',
					},
					riding: {
						duration: '',
						distance: '',
					},
					walking: {
						duration: '',
						distance: '',
					}
				},
				landlordInfo: {},
				principalInfo: {},
				adminList: [],
				principal: '', //负责人
				pvisible: false,
				publishAudit: null,
				addresslist: [],
				dialogVisible: false,
				options: regionData,
				show: false,
				visible: false, //确认删除弹框
				houseInfo: {},
				imageList: [],
				form: {
					selectedOptions: null, //选中的项目
					description: '',
					address: '',
					detailedAddress: '',
					decorationStyle: '简装修',
					area: '',
					rooms: 0,
					halls: 0,
					bathrooms: 0,
					price: 0,
					lat: 0,
					lng: 0,
					orientation: [],
				},
				userpreferences: {},
				rules: {
					location: [{
						required: true,
						validator: validatePass,
						trigger: 'blur',
						// message: '请选择'
					}],
					address: [{
						required: true,
						trigger: 'blur',
						message: '请输入并选择'
					}],
					detailedAddress: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
					price: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
					area: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
					orientation: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
				},
			}
		},

		activated() {
			if (!this.$route.params.isAdmin) {
				this.$axios.get(this.common.backendURL + '/api/user/checkCollection?houseId=' + this.$route.params.index).then(
					res => {
						if (res.data == true) {
							this.plain = false
						} else {
							this.plain = true
						}
					})
				this.$axios.get(this.common.backendURL + '/api/order/isBooked?houseId=' + this.$route.params.index).then(
					res => {
						if (res.data == true) {
							this.bookButtonDisabled = true
						} else {
							this.bookButtonDisabled = false
						}
					})
			}
			this.show = false
			this.publishAudit = null
			this.$axios.get(this.common.backendURL + '/api/house/getById?id=' + this.$route.params.index).then(res => {
				this.houseInfo = res.data.data
				if (this.$route.params.isAdmin) {
					this.$refs.recommendeduser.render()
				}
				this.imageList = JSON.parse(res.data.data.pictureList)
				//编辑对话框数据载入
				this.form.orientation = this.houseInfo.orientation.split(',')
				this.form.description = this.houseInfo.description
				this.form.selectedOptions = [this.houseInfo.province, this.houseInfo.city, this.houseInfo.region]
				this.form.address = this.houseInfo.address
				this.form.detailedAddress = this.houseInfo.detailedAddress
				this.form.price = this.houseInfo.price
				this.form.area = this.houseInfo.area
				this.form.decorationStyle = this.houseInfo.decorationStyle == 0 ? '简装修' : '精装修'
				this.form.rooms = this.houseInfo.rooms
				this.form.halls = this.houseInfo.halls
				this.form.bathrooms = this.houseInfo.bathrooms
				this.form.lat = this.houseInfo.latitude
				this.form.lng = this.houseInfo.longitude
				//计算距离，通勤时间（用户端）
				if (this.$route.params.isAdmin == false) {
					this.$axios.get(this.common.backendURL + '/api/user/getById?id=' + this.$route.params.userid).then(res => {
						this.userpreferences = res.data.data.preferences == null ? '未设定' : JSON.parse(res.data.data
							.preferences)
						if (this.userpreferences != '未设定') {
							this.$axios.get(this.common.backendURL + `/api/house/calDistance?hlng=${this.houseInfo.longitude}&hlat=${this.houseInfo.latitude}
					&ulng=${this.userpreferences.lng}&ulat=${this.userpreferences.lat}&type=transit`).then(res => {
								if (res.data.data.status == 0) {
									this.distanceInfo.transit.distance = res.data.data.result.routes[0].distance
									this.distanceInfo.transit.duration = '约 ' + this.formatSeconds(res.data.data.result.routes[
										0].duration)
								} else {
									this.distanceInfo.transit.distance = "-"
									this.distanceInfo.transit.duration = "-"
								}
							})
							this.$axios.get(this.common.backendURL + `/api/house/calDistance?hlng=${this.houseInfo.longitude}&hlat=${this.houseInfo.latitude}
				&ulng=${this.userpreferences.lng}&ulat=${this.userpreferences.lat}&type=driving`).then(res => {
								if (res.data.data.status == 0) {
									this.distanceInfo.driving.distance = res.data.data.result.routes[0].distance
									this.distanceInfo.driving.duration = '约 ' + this.formatSeconds(res.data.data.result.routes[
											0]
										.duration)
								} else {
									this.distanceInfo.driving.distance = "-"
									this.distanceInfo.driving.duration = "-"
								}
							})
							this.$axios.get(this.common.backendURL + `/api/house/calDistance?hlng=${this.houseInfo.longitude}&hlat=${this.houseInfo.latitude}
					&ulng=${this.userpreferences.lng}&ulat=${this.userpreferences.lat}&type=riding`).then(res => {
								if (res.data.data.status == 0) {
									this.distanceInfo.riding.distance = res.data.data.result.routes[0].distance
									this.distanceInfo.riding.duration = '约 ' + this.formatSeconds(res.data.data.result.routes[
											0]
										.duration)
								} else {
									this.distanceInfo.riding.distance = "-"
									this.distanceInfo.riding.duration = "-"
								}
							})
							this.$axios.get(this.common.backendURL + `/api/house/calDistance?hlng=${this.houseInfo.longitude}&hlat=${this.houseInfo.latitude}
						&ulng=${this.userpreferences.lng}&ulat=${this.userpreferences.lat}&type=walking`).then(res => {
								if (res.data.data.status == 0) {
									this.distanceInfo.walking.distance = res.data.data.result.routes[0].distance
									this.distanceInfo.walking.duration = '约 ' + this.formatSeconds(res.data.data.result.routes[
											0]
										.duration)
								} else {
									this.distanceInfo.walking.distance = "-"
									this.distanceInfo.walking.duration = "-"
								}
							})
						}
					})
				}

				//获取房源审核数据
				this.$axios.get(this.common.backendURL + '/api/getPublish?houseId=' + this.houseInfo.id).then(
					res => {
						if (res.data.code == 1) {
							this.publishAudit = res.data.data;
						}
						var url = '/api/user/getById?id='
						if (this.houseInfo.addType == 1) {
							url = '/api/manager/getById?id='
						}
						this.$axios.get(this.common.backendURL + url + this.houseInfo.addUserid).then(
							res => {
								if (res.data.code == 1) {
									this.landlordInfo = res.data.data;
								}
								if (this.houseInfo.status == 1) {
									this.$axios.get(this.common.backendURL +
										'/api/getPrincipalInfo?username=' + this.publishAudit[2]).then(
										res => {
											if (res.data.code == 1) {
												this.principalInfo = res.data.data;
											}
										})
								}
							})
					})
				this.$axios.get(this.common.backendURL + '/api/manager/listAllIdAndName').then(
					res => {
						if (res.data.code == 1) {
							this.adminList = res.data.data;
						}
					})
				//渲染百度地图
				var map = new BMapGL.Map("container");
				map.enableScrollWheelZoom(true);
				var scaleCtrl = new BMapGL.ScaleControl(); // 添加比例尺控件
				map.addControl(scaleCtrl);
				var zoomCtrl = new BMapGL.ZoomControl(); // 添加缩放控件
				map.addControl(zoomCtrl);
				this.common.setTime(() => {
					var point = new BMapGL.Point(this.houseInfo.longitude, this.houseInfo.latitude);
					map.centerAndZoom(point, 16);
					var marker = new BMapGL.Marker(point); // 创建标注
					map.addOverlay(marker); // 将标注添加到地图中
				}, 50)
			})
			this.common.setTime(() => {
				this.show = true
			}, 50)
		},

		computed: {
			postform() {
				return {
					id: this.$route.params.index,
					description: this.form.description,
					price: this.form.price,
					longitude: this.form.lng,
					latitude: this.form.lat,
					province: this.form.selectedOptions[0],
					city: this.form.selectedOptions[1],
					region: this.form.selectedOptions[2],
					address: this.form.address,
					detailedAddress: this.form.detailedAddress,
					area: this.form.area,
					decorationStyle: this.form.decorationStyle == '简装修' ? 0 : 1,
					rooms: this.form.rooms,
					halls: this.form.halls,
					bathrooms: this.form.bathrooms,
					orientation: this.form.orientation.join(),
				}
			},
			location() {
				return CodeToText[this.houseInfo.province] + CodeToText[this.houseInfo.city] + CodeToText[this.houseInfo
					.region]
			},
			decorationStyle() {
				return this.houseInfo.decorationStyle == 0 ? '简装修' : '精装修'
			},
			mapurl() {
				return 'http://api.map.baidu.com/staticimage/v2?ak=' + this.common.ak + '&center=' +
					this.houseInfo.longitude + ',' + this.houseInfo.latitude +
					'&width=1024&height=450&zoom=16&copyright=1&markers=' + this.houseInfo
					.longitude + ',' + this.houseInfo.latitude
			},
			status() {
				if (this.houseInfo.status == 0) {
					return '待审核'
				} else if (this.houseInfo.status == 1) {
					return '已发布'
				} else if (this.houseInfo.status == 2) {
					return '已租出'
				} else if (this.houseInfo.status == 3) {
					return '被锁定'
				} else {
					return '未知'
				}

			},
			hasmap() {
				if (this.houseInfo.longitude != 0 && this.houseInfo.latitude != 0) {
					return true
				} else return false
			},
			city() {
				return CodeToText[this.form.selectedOptions[1]] == '市辖区' ? CodeToText[this.form.selectedOptions[0]] :
					CodeToText[this.form.selectedOptions[1]]
			},
			getprincipal() {
				return this.principal == '' ? -1 : this.principal
			},
		},
		methods: {
			formatSeconds(value) {
				var secondTime = parseInt(value); // 秒
				var minuteTime = 0; // 分
				var hourTime = 0; // 小时
				if (secondTime > 60) { //如果秒数大于60，将秒数转换成整数
					//获取分钟，除以60取整数，得到整数分钟
					minuteTime = parseInt(secondTime / 60);
					//获取秒数，秒数取佘，得到整数秒数
					secondTime = parseInt(secondTime % 60);
					//如果分钟大于60，将分钟转换成小时
					if (minuteTime > 60) {
						//获取小时，获取分钟除以60，得到整数小时
						hourTime = parseInt(minuteTime / 60);
						//获取小时后取佘的分，获取分钟除以60取佘的分
						minuteTime = parseInt(minuteTime % 60);
					}
				}
				var result = "" + parseInt(secondTime) + " 秒";

				if (minuteTime > 0) {
					result = "" + parseInt(minuteTime) + " 分 " + result;
				}
				if (hourTime > 0) {
					result = "" + parseInt(hourTime) + " 小时 " + result;
				}
				return result;
			},
			onClickDelete() {
				this.$axios.get(this.common.backendURL + '/api/house/delById?id=' + this.$route.params.index).then((
					res) => {
					if (res.data.code == 1) {
						this.$message.success('删除成功')
						this.$router.back()
					} else {
						this.$message.error(res.data.msg)
					}
				})
			},
			querySearch(queryString, cb) { //请求百度api取得地址输入建议列表
				this.$jsonp('http://api.map.baidu.com/place/v2/suggestion?query=' + queryString +
						'&region=' + this.city + '&city_limit=true&output=json&ak=' + this.common.ak)

					// this.$axios.get(this.common.backendURL+'/api/house/getRecommendList?query=' + queryString +
					// 		'&region=' + this.city + '&ak=' + this.common.ak)
					.then((response) => {
						this.addresslist = response.result
						var results = [];
						for (var i = 0; i < this.addresslist.length; i++) {
							results[i] = {
								"value": this.addresslist[i].name,
								"index": i,
							};
						}
						// 调用 callback 返回建议列表的数据
						cb(results);
					})
			},
			handleSelect(item) {
				this.form.lat = this.addresslist[item.index].location.lat
				this.form.lng = this.addresslist[item.index].location.lng
			},
			handleChange() {
				this.form.lat = 0
				this.form.lng = 0
				this.form.address = ''
				this.form.detailedAddress = ''
			},
			onClickDialogConfirm() {
				this.$axios.post(this.common.backendURL + '/api/house/updateById', this.postform).then((res) => {
					if (res.data.code == 1) {
						this.$message.success('修改成功')
						this.dialogVisible = false
						this.$router.back()
					} else {
						this.$message.error('修改失败')
					}
				})
			},
			onClickPublishConfirm() {
				if (this.principal == '') {
					this.$message.warning('请指定中介负责人')
				} else {
					this.$axios.get(this.common.backendURL + '/api/audit?houseId=' + this.$route.params.index +
						'&adminId=' +
						this.$route.params.userid + '&type=0&principal=' + this.getprincipal).then(res => {
						if (res.data.code == 1) {
							this.$message.success('发布成功')
							this.pvisible = false
							this.$router.back()
						} else {
							this.$message.error('发布失败，数据库错误')
						}
					})
				}
			},
			onClickLock() {
				this.$axios.get(this.common.backendURL + '/api/audit?houseId=' + this.$route.params.index + '&adminId=' +
					this.$route.params.userid + '&type=1').then(res => {
					if (res.data.code == 1) {
						this.$message.success('锁定成功')
						this.$router.back()
					} else {
						this.$message.error('锁定失败，数据库错误')
					}
				})
			},
			onClickRecover() {
				this.$axios.get(this.common.backendURL + '/api/audit?houseId=' + this.$route.params.index + '&adminId=' +
					this.$route.params.userid + '&type=2').then(res => {
					if (res.data.code == 1) {
						this.$message.success('恢复成功')
						this.$router.back()
					} else {
						this.$message.error('恢复失败，数据库错误')
					}
				})
			},
			onClickCollect() {
				if (this.plain == true) {
					//收藏
					this.$axios.get(this.common.backendURL + '/api/user/userAddCollection?houseId=' + this.$route.params.index)
						.then(res => {
							if (res.data.code == 1) {
								this.$message.success('收藏成功')
								this.plain = false
							} else {
								this.$message.error('收藏失败')
							}
						})
				} else {
					//取消收藏
					this.$axios.get(this.common.backendURL + '/api/user/userCancelCollection?houseId=' + this.$route.params.index)
						.then(res => {
							if (res.data.code == 1) {
								this.$message.success('取消收藏成功')
								this.plain = true
							} else {
								this.$message.error('取消收藏失败')
							}

						})

				}
			},
			onClickConfirmBooking() {
				this.bookpopvisible = false
				//TODO: 发起订单
				this.$axios.get(this.common.backendURL + '/api/order/book?houseId=' + this.$route.params.index + '&duration=' +
					this.bookingduration).then(res => {
					if (res.data.code == 1) {
						this.$message.success('预定成功')
						this.bookButtonDisabled = true
					} else {
						this.$message.error('预定失败')
					}
				})
			},
			back() {
				this.$router.back()
			}
		},
		components: {
			RecommendedUser
		}
	}
</script>

