<template>
	<div class="container">
		<h3>房客匹配（按匹配度排序）</h3>
		<el-card v-for="(item,index) in userData"
			style="float: left;width: 230px;height: 230px;margin-right: 20px;margin-bottom: 20px;">
			
			<i style="font-size: 20px;" class="el-icon-user-solid"></i>
			<span style="font-size: 20px;"> {{item.username}}</span>
			<el-divider></el-divider>
			<el-descriptions :column="1" border>
				<el-descriptions-item>
					<template slot="label">
						姓名
					</template>
					{{item.name}}
				</el-descriptions-item>
				<el-descriptions-item>
					<template slot="label">
						手机号
					</template>
					{{item.phone}}
				</el-descriptions-item>
			
				</el-descriptions>
		</el-card>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				userData: []
			}
		},
		methods: {

		},
		activated() {

		},
		methods: {
			render() {
				var o = []
				o = this.$parent.houseInfo.orientation
				this.$axios.post(this.common.backendURL + '/api/user/listRecommendedUsers', {
					//房屋特征向量【面积，精装修，室，厅，卫，朝东，朝南，朝西，朝北，经度，纬度】
					destination: [this.$parent.houseInfo.province, this.$parent.houseInfo.city, this.$parent.houseInfo.region],
					lat: this.$parent.houseInfo.latitude,
					lng: this.$parent.houseInfo.longitude,
					area: this.$parent.houseInfo.area,
					decorationStyle: this.$parent.houseInfo.decorationStyle,
					rooms: this.$parent.houseInfo.rooms,
					halls: this.$parent.houseInfo.halls,
					bathrooms: this.$parent.houseInfo.bathrooms,
					orientation: o.split(',')
				}).then(res => {
					if (res.data.code == 1) {
						this.userData = res.data.data
					}
				})
			}
		}
	}
</script>

<style scoped>
	.container {
		width: 1024px;
		padding-left: 20px;
		padding-right: 20px;
		margin: 0 auto;
		overflow: hidden;
	}
</style>